CREATE MACRO human_bytes (size) AS (CASE  WHEN ((size IS NULL)) THEN (NULL) WHEN ((size < 1024)) THEN ((CAST(size AS VARCHAR) || ' B')) WHEN ((size < power(1024, 2))) THEN ((round((size / 1024.0), 2) || ' KiB')) WHEN ((size < power(1024, 3))) THEN ((round((size / power(1024.0, 2)), 2) || ' MiB')) WHEN ((size < power(1024, 4))) THEN ((round((size / power(1024.0, 3)), 2) || ' GiB')) WHEN ((size < power(1024, 5))) THEN ((round((size / power(1024.0, 4)), 2) || ' TiB')) ELSE (round((size / power(1024.0, 5)), 2) || ' PiB') END);;

